sql.where:
f.deleted = 0
AND f.enabled = #{query.enabled}
AND f.enabled = 1
AND ( f.name LIKE CONCAT('%', #{query.keyword}, '%') OR f.formatted_address LIKE CONCAT('%', #{query.keyword}, '%') OR f.location_desc LIKE CONCAT('%', #{query.keyword}, '%') OR f.province LIKE CONCAT('%', #{query.keyword}, '%') OR f.city LIKE CONCAT('%', #{query.keyword}, '%') OR f.district LIKE CONCAT('%', #{query.keyword}, '%') OR f.township LIKE CONCAT('%', #{query.keyword}, '%') OR f.crop_type LIKE CONCAT('%', #{query.keyword}, '%') OR f.crop_variety LIKE CONCAT('%', #{query.keyword}, '%') OR f.crop_variety_groups_json LIKE CONCAT('%', #{query.keyword}, '%') OR EXISTS ( SELECT 1 FROM field_crop_cycle c WHERE c.field_id = f.id AND c.deleted = 0 AND c.status = 'active' AND c.crops_json LIKE CONCAT('%', #{query.keyword}, '%') ) )
AND f.status = #{query.status}
AND ( f.crop_type = #{query.cropType}
OR f.crop_variety_groups_json LIKE CONCAT('%', #{query.cropTypeJsonToken}, '%')
OR EXISTS ( SELECT 1 FROM field_crop_cycle c WHERE c.field_id = f.id AND c.deleted = 0 AND c.status = 'active' AND c.crops_json LIKE CONCAT('%', #{query.cycleCropTypeJsonToken}, '%') )
)
AND f.province LIKE CONCAT('%', #{query.province}, '%')
AND f.city LIKE CONCAT('%', #{query.city}, '%')
AND f.district LIKE CONCAT('%', #{query.district}, '%')
AND f.township LIKE CONCAT('%', #{query.township}, '%')
AND ( f.crop_variety LIKE CONCAT('%', #{query.cropVariety}, '%')
OR f.crop_variety_groups_json LIKE CONCAT('%', #{query.cropVarietyJsonToken}, '%')
OR EXISTS ( SELECT 1 FROM field_crop_cycle c WHERE c.field_id = f.id AND c.deleted = 0 AND c.status = 'active' AND c.crops_json LIKE CONCAT('%', #{query.cycleCropVarietyJsonToken}, '%') )
)
AND f.location_point IS NOT NULL AND f.location_lat BETWEEN -90 AND 90 AND f.location_lng BETWEEN -180 AND 180
AND f.location_point IS NOT NULL AND f.location_lat BETWEEN -90 AND 90 AND f.location_lng BETWEEN -180 AND 180 AND MBRContains( ST_GeomFromText(#{query.envelopeWkt}), f.location_point )
AND f.location_point IS NOT NULL AND f.location_lat BETWEEN -90 AND 90 AND f.location_lng BETWEEN -180 AND 180 AND ST_Distance_Sphere( f.location_point, ST_GeomFromText(#{query.queryPointWkt}) ) <= #{query.radiusMeters}
